using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new ShoppingCart();

    // в”Җв”Җ AddItem в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _sut.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(1, _sut.Items.Count);
        Assert.AreEqual(2, _sut.Items["SKU-1"].Quantity);
        Assert.AreEqual(9.99m, _sut.Items["SKU-1"].Price);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantityAndUsesLatestPrice()
    {
        _sut.AddItem("SKU-1", 1, 5.00m);
        _sut.AddItem("SKU-1", 3, 6.00m);

        Assert.AreEqual(1, _sut.Items.Count);
        Assert.AreEqual(4, _sut.Items["SKU-1"].Quantity);
        Assert.AreEqual(6.00m, _sut.Items["SKU-1"].Price);
    }

    [TestMethod]
    public void AddItem_MultipleSkus_AllAppearInCart()
    {
        _sut.AddItem("A", 1, 10m);
        _sut.AddItem("B", 2, 20m);

        Assert.AreEqual(2, _sut.Items.Count);
    }

    [TestMethod]
    [DataRow(null, DisplayName = "null SKU")]
    [DataRow("", DisplayName = "empty SKU")]
    [DataRow("   ", DisplayName = "whitespace SKU")]
    public void AddItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem(sku!, 1, 10m));
    }

    [TestMethod]
    [DataRow(0, DisplayName = "zero quantity")]
    [DataRow(-1, DisplayName = "negative quantity")]
    public void AddItem_InvalidQuantity_Throws(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-1", quantity, 10m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-1", 1, -1m));
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Succeeds()
    {
        _sut.AddItem("FREE", 1, 0m);

        Assert.AreEqual(0m, _sut.Items["FREE"].Price);
    }

    // в”Җв”Җ RemoveItem в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _sut.AddItem("SKU-1", 1, 10m);

        _sut.RemoveItem("SKU-1");

        Assert.AreEqual(0, _sut.Items.Count);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFoundException()
    {
        Assert.ThrowsException<KeyNotFoundException>(
            () => _sut.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "null SKU")]
    [DataRow("", DisplayName = "empty SKU")]
    public void RemoveItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.RemoveItem(sku!));
    }

    // в”Җв”Җ CalculateTotal в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsQuantityTimesPrice()
    {
        _sut.AddItem("SKU-1", 3, 10m);

        Assert.AreEqual(30m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfAll()
    {
        _sut.AddItem("A", 2, 5m);   // 10
        _sut.AddItem("B", 1, 20m);  // 20

        Assert.AreEqual(30m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemovingItem_ExcludesRemovedItem()
    {
        _sut.AddItem("A", 1, 10m);
        _sut.AddItem("B", 1, 20m);
        _sut.RemoveItem("A");

        Assert.AreEqual(20m, _sut.CalculateTotal());
    }

    // в”Җв”Җ ApplyCoupon в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    [DataRow("SAVE10", 10, DisplayName = "SAVE10 вҶ’ 10% off")]
    [DataRow("SAVE20", 20, DisplayName = "SAVE20 вҶ’ 20% off")]
    [DataRow("HALF", 50, DisplayName = "HALF вҶ’ 50% off")]
    public void ApplyCoupon_ValidCode_ReducesTotal(string code, int discountPercent)
    {
        _sut.AddItem("SKU-1", 1, 100m);
        _sut.ApplyCoupon(code);

        var expected = 100m - (100m * discountPercent / 100m);
        Assert.AreEqual(expected, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive_AppliesDiscount()
    {
        _sut.AddItem("SKU-1", 1, 100m);
        _sut.ApplyCoupon("save10");

        Assert.AreEqual(90m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "null code")]
    [DataRow("", DisplayName = "empty code")]
    public void ApplyCoupon_NullOrEmpty_Throws(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_ReplacedBySecondCoupon_UsesLatest()
    {
        _sut.AddItem("SKU-1", 1, 100m);
        _sut.ApplyCoupon("SAVE10");
        _sut.ApplyCoupon("SAVE20");

        Assert.AreEqual(80m, _sut.CalculateTotal());
    }

    // в”Җв”Җ End-to-end scenario в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public void FullWorkflow_AddRemoveCoupon_CorrectTotal()
    {
        _sut.AddItem("SHIRT", 2, 25m);   // 50
        _sut.AddItem("HAT", 1, 15m);     // 15
        _sut.RemoveItem("HAT");           // -15
        _sut.ApplyCoupon("SAVE10");       // 10% off 50 = 45

        Assert.AreEqual(45m, _sut.CalculateTotal());
    }
}

